/**
 * Centralized token resolver — single chokepoint for all GitHub API auth.
 *
 * Resolution order:
 * 1. If repoFullName provided → look up installation for that repo → installation token
 * 2. Else if user has service='github' credential → OAuth token (legacy)
 * 3. Else if user has service='github_app' credential → GitHub App user token (with refresh)
 * 4. Return null if none exist
 */
export async function resolveGitHubToken(
  userId: string,
  repoFullName?: string
): Promise<ResolvedToken | null> {
  // Path A: repo-scoped — check for GitHub App installation
  if (repoFullName) {
    const repoRow = await installationRepoOps.findByUserAndRepo(userId, repoFullName) as any;
    if (repoRow?.installationId) {
      try {
        const token = await githubAppService.getInstallationToken(repoRow.installationId);
        // Also grab OAuth token for identity lookups (installation tokens can't call /user)
        const oauthCred = await credentialOps.findByUserAndService(userId, 'github') as any;
        const oauthToken = oauthCred?.encryptedValue ? decryptValue(oauthCred.encryptedValue) : null;
        const appToken = oauthToken || await resolveGitHubAppCredential(userId);
        return { token, source: 'installation', oauthToken: appToken || undefined };
      } catch (err) {
        console.warn(`[resolveGitHubToken] Installation token failed for ${repoFullName}, falling back to OAuth:`, (err as Error).message);
        // Fall through to OAuth
      }
    }
  }

  // Path B: user-scoped / fallback — legacy OAuth token (service='github')
  const credential = await credentialOps.findByUserAndService(userId, 'github') as any;
  if (credential?.encryptedValue) {
    return { token: decryptValue(credential.encryptedValue), source: 'oauth' };
  }

  // Path C: GitHub App user token (service='github_app', with auto-refresh)
  const appToken = await resolveGitHubAppCredential(userId);
  if (appToken) {
    return { token: appToken, source: 'github_app' };
  }

  return null;
}

