router.get('/github/app/status', requireAuth, async (req, res) => {
  const user = req.user as AuthUser;

  const rawInstallations = await installationOps.findByUserId(user.id) as any[];
  const installations = [];
  for (const inst of rawInstallations) {
    const repos = await installationRepoOps.findByInstallation(inst.installationId);
    installations.push({
      ...inst,
      permissions: inst.permissions ? JSON.parse(inst.permissions) : null,
      repos,
    });
  }

  const credential = await credentialOps.findByUserAndService(user.id, 'github_app') as any;

  // Count linked projects and find unlinkable projects
  const userProjects = await projectOps.findByUserId(user.id) as any[];
  const linkedProjects = userProjects.filter((p: any) => p.installationId).length;
  const unlinkableProjects = userProjects
    .filter((p: any) => p.githubRepo && !p.installationId)
    .map((p: any) => ({ id: p.id, name: p.name, repo: p.githubRepo }));

  res.json({
    configured: githubAppService.isConfigured(),
    installations,
    userToken: credential ? { connectedAt: credential.createdAt } : null,
    linkedProjects,
    unlinkableProjects,
  });
});

