/**
 * Verify that the resolved token can access a specific repo.
 * Lightweight check (GET /repos/{owner}/{repo}) before expensive operations.
 */
async verifyRepoAccess(
  userId: string,
  owner: string,
  repo: string
): Promise<{ accessible: boolean; reason?: string; message: string }> {
  const repoFullName = `${owner}/${repo}`;
  const token = await this.getAccessToken(userId, repoFullName);

  if (!token) {
    return {
      accessible: false,
      reason: 'no_token',
      message: 'Connect GitHub to allow DevDash to access your code.',
    };
  }

  try {
    const response = await fetch(`${this.baseUrl}/repos/${owner}/${repo}`, {
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: 'application/vnd.github.v3+json',
        'User-Agent': 'Dev-Dash',
      },
    });

    if (response.ok) {
      return { accessible: true, message: 'OK' };
    }

    if (response.status === 404) {
      return {
        accessible: false,
        reason: 'not_found',
        message: `Repository ${repoFullName} not found. Check the name or install the Dev-Dash GitHub App on this repo.`,
      };
    }

    if (response.status === 401 || response.status === 403) {
      return {
        accessible: false,
        reason: 'no_permission',
        message: `No access to ${repoFullName}. Install the Dev-Dash GitHub App or reconnect GitHub in Settings.`,
      };
    }

    return {
      accessible: false,
      reason: 'api_error',
      message: `GitHub API returned ${response.status} for ${repoFullName}. Try again later.`,
    };
  } catch (err) {
    return {
      accessible: false,
      reason: 'network_error',
      message: `Could not reach GitHub API to verify access to ${repoFullName}.`,
    };
  }
}

