router.get('/:id/repo-status', async (req, res) => {
  const project = await requireProjectAccess(req.params.id, req.user!.id);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  const githubRepo = (project as any).githubRepo;
  if (!githubRepo) {
    return res.json({ linked: false, message: 'No GitHub repository linked.' });
  }

  const [owner, repo] = githubRepo.split('/');
  if (!owner || !repo) {
    return res.json({ linked: true, accessible: false, reason: 'invalid_format', message: `Invalid repo format: ${githubRepo}` });
  }

  try {
    const result = await githubService.verifyRepoAccess(req.user!.id, owner, repo);
    res.json({ linked: true, ...result });
  } catch (error) {
    console.error('Error checking repo access:', error);
    res.json({ linked: true, accessible: false, reason: 'api_error', message: 'Failed to check repository access.' });
  }
});

