export const githubAppService = new GitHubAppService();

export interface ResolvedToken {
  token: string;
  source: 'installation' | 'oauth' | 'github_app';
  /** OAuth token for identity lookups when primary token is an installation token */
  oauthToken?: string;
}

/**
 * Resolve a GitHub App user token (service='github_app'), refreshing if expired.
 * Returns the access_token or null if no credential exists or refresh fails.
 */
async function resolveGitHubAppCredential(userId: string): Promise<string | null> {
  const credential = await credentialOps.findByUserAndService(userId, 'github_app') as any;
  if (!credential?.encryptedValue) return null;

  let parsed: any;
  try {
    const plaintext = decryptValue(credential.encryptedValue);
    parsed = JSON.parse(plaintext);
  } catch {
    console.warn(`[resolveGitHubAppCredential] Failed to decrypt/parse github_app credential for user ${userId}`);
    return null;
  }

  if (!parsed.access_token) return null;

  // Check expiration: created_at (epoch ms or ISO) + expires_in (seconds)
  const createdAt = typeof parsed.created_at === 'number'
    ? parsed.created_at
    : (parsed.created_at ? new Date(parsed.created_at).getTime() : 0);
  const expiresIn = parsed.expires_in || 0;

  if (createdAt && expiresIn) {
    const expiresAt = createdAt + expiresIn * 1000;
    // Refresh 5 minutes before expiry
    if (expiresAt - Date.now() < 5 * 60 * 1000) {
      if (!parsed.refresh_token) {
        console.warn(`[resolveGitHubAppCredential] Token expired and no refresh_token for user ${userId}`);
        return null;
      }

      try {
        console.log(`[resolveGitHubAppCredential] Refreshing expired token for user ${userId}`);
        const refreshed = await githubAppService.refreshUserToken(parsed.refresh_token);

        // Persist refreshed tokens
        const newPlaintext = JSON.stringify({
          access_token: refreshed.access_token,
          refresh_token: refreshed.refresh_token,
          expires_in: refreshed.expires_in,
          refresh_token_expires_in: refreshed.refresh_token_expires_in,
          created_at: Date.now(),
        });
        const newEncrypted = encryptValue(newPlaintext);
        await credentialOps.upsert(
          credential.id,
          userId,
          'github_app',
          'oauth',
          newEncrypted,
          null, // expires_at — computed from JSON fields
          'oauth', newEncrypted, null
        );
        console.log(`[resolveGitHubAppCredential] Token refreshed successfully for user ${userId}`);
        return refreshed.access_token;
      } catch (err) {
        console.warn(`[resolveGitHubAppCredential] Token refresh failed for user ${userId}:`, (err as Error).message);
        return null;
      }
    }
  }

  return parsed.access_token;
}

