  private tokenCache = new Map<number, CachedToken>();

  /** Check if all required env vars are set */
  isConfigured(): boolean {
    return !!(GITHUB_APP_ID && GITHUB_APP_PRIVATE_KEY && GITHUB_APP_CLIENT_ID && GITHUB_APP_CLIENT_SECRET);
  }

  /** Generate a short-lived JWT for authenticating as the GitHub App itself */
  generateAppJWT(): string {
    const now = Math.floor(Date.now() / 1000);
    return jwt.sign(
      {
        iat: now - 60, // issued 60s ago to account for clock drift
        exp: now + 10 * 60, // 10-minute expiry (GitHub max)
        iss: GITHUB_APP_ID,
      },
      GITHUB_APP_PRIVATE_KEY,
      { algorithm: 'RS256' }
    );
  }

  /** Get an installation access token (cached, refreshes 5 min before expiry) */
  async getInstallationToken(installationId: number): Promise<string> {
    const cached = this.tokenCache.get(installationId);
    if (cached && cached.expiresAt.getTime() - Date.now() > 5 * 60 * 1000) {
      return cached.token;
    }

    const appJWT = this.generateAppJWT();
    const response = await fetch(
      `https://api.github.com/app/installations/${installationId}/access_tokens`,
      {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${appJWT}`,
          Accept: 'application/vnd.github+json',
          'X-GitHub-Api-Version': '2022-11-28',
        },
      }
    );

    if (!response.ok) {
      const body = await response.text();
      throw new Error(`Failed to get installation token: ${response.status} ${body}`);
    }

    const data = await response.json() as { token: string; expires_at: string };
    this.tokenCache.set(installationId, {
      token: data.token,
      expiresAt: new Date(data.expires_at),
    });

    return data.token;
  }

  /** List repos accessible to an installation (paginated) */
  async getInstallationRepos(installationId: number): Promise<Array<{ id: number; full_name: string; private: boolean }>> {
    const token = await this.getInstallationToken(installationId);
    const repos: Array<{ id: number; full_name: string; private: boolean }> = [];
    let page = 1;

    while (true) {
      const response = await fetch(
        `https://api.github.com/installation/repositories?per_page=100&page=${page}`,
        {
          headers: {
            Authorization: `token ${token}`,
            Accept: 'application/vnd.github+json',
            'X-GitHub-Api-Version': '2022-11-28',
          },
        }
      );

      if (!response.ok) break;

      const data = await response.json() as { repositories: Array<{ id: number; full_name: string; private: boolean }> };
      repos.push(...data.repositories.map(r => ({ id: r.id, full_name: r.full_name, private: r.private })));

      if (data.repositories.length < 100) break;
      page++;
    }

    return repos;
  }

  /** Verify a webhook payload signature (HMAC-SHA256) */
  verifyWebhookSignature(payload: Buffer, signature: string): boolean {
    if (!GITHUB_APP_WEBHOOK_SECRET) return false;

    const expected = 'sha256=' + crypto
      .createHmac('sha256', GITHUB_APP_WEBHOOK_SECRET)
      .update(payload)
      .digest('hex');

    if (expected.length !== signature.length) return false;

    return crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(signature));
  }

