 * POST /api/jobs/analyze - Queue an analysis job to run in an E2B sandbox.
 * Returns immediately with a jobId; the dispatcher picks up the job and
 * runs task analysis in a sandbox with real file access.
 */
router.post('/analyze', validate({ body: AnalyzeJobBody }), async (req, res) => {
  try {
    const { projectId, prompt, beadId } = req.body as AnalyzeJobBody;
    const userId = (req.user as any).id;

    const project = await requirePermission(projectId, userId, 'manage_tasks');
    if (!project) {
      return res.status(403).json({ error: 'manage_tasks permission required' });
    }
    if (!project.githubRepo) {
      return res.status(400).json({ error: 'Project has no GitHub repository connected' });
    }

    // Guard: thoughts cannot be analyzed
    if (beadId) {
      const bead = await beadOps.findById(beadId) as any;
      if (bead?.beadType === 'thought') {
        return res.status(400).json({ error: 'Thoughts cannot be analyzed' });
      }
    }

    // When analyzing a bead, always use subject + description as the prompt
    // so the analyzer sees the task intent, not stale preInstructions
    let analyzerPrompt = prompt;
    if (beadId) {
      const bead = await beadOps.findById(beadId) as any;
      if (bead && bead.projectId === projectId) {
        analyzerPrompt = bead.description
          ? `${bead.subject}\n\n${bead.description}`
          : bead.subject;
      }
    }

    // Queue analysis job — dispatcher will pick it up and run in E2B sandbox
    const analysisJob = await jobQueue.createJob({
      projectId,
      beadId: beadId || undefined,
      prompt: analyzerPrompt,
      jobType: 'analysis',
      dispatchedBy: userId,
      skipDuplicateCheck: true, // Allow multiple analysis runs per bead
    });
    projectEvents.emit('change', { type: 'jobs:changed', projectId });

    res.json({ jobId: analysisJob.id, status: 'queued' });
  } catch (error) {
    console.error('Error queuing analysis job:', error);
    const message = error instanceof Error ? error.message : 'Failed to queue analysis';

