router.get('/github/app', requireAuth, (req, res) => {
  const user = req.user as AuthUser;

  if (!githubAppService.isConfigured()) {
    return res.status(503).json({ error: 'GitHub App is not configured' });
  }

  // Accept optional redirect path (e.g. /onboarding)
  const redirect = typeof req.query.redirect === 'string' ? req.query.redirect : undefined;

  // JWT-signed state param (userId + purpose + redirect, 15-min expiry)
  const state = jwt.sign(
    { userId: user.id, purpose: 'github_app_install', redirect },
    process.env.SESSION_SECRET || 'dev-secret-change-in-production',
    { expiresIn: '15m' }
  );

  res.redirect(`https://github.com/apps/dev-dash-project/installations/new?state=${encodeURIComponent(state)}`);
});

