#!/usr/bin/env npx tsx
/**
 * SQLite → Postgres data migration script.
 *
 * Reads all data from the SQLite database and inserts it into Postgres
 * in FK-dependency order. Handles type conversions:
 * - datetime strings �� Postgres timestamps
 * - INTEGER 0/1 → boolean true/false
 * - NULL handling
 *
 * Usage:
 *   POSTGRES_URL="postgresql://..." SQLITE_PATH="./data/devdash.db" npx tsx scripts/migrate-sqlite-to-postgres.ts
 *
 * Options:
 *   --dry-run     Print counts but don't insert
 *   --truncate    Truncate Postgres tables before inserting (DANGEROUS)
 *   --upsert      Use ON CONFLICT DO UPDATE to overwrite existing rows (for delta migrations)
 */

import pg from 'pg';
import Database from 'better-sqlite3';

const POSTGRES_URL = process.env.POSTGRES_URL;
const SQLITE_PATH = process.env.SQLITE_PATH || './data/devdash.db';
const DRY_RUN = process.argv.includes('--dry-run');
const TRUNCATE = process.argv.includes('--truncate');
const UPSERT = process.argv.includes('--upsert');

if (!POSTGRES_URL) {
  console.error('POSTGRES_URL env var required');
  process.exit(1);
}

const sqlite = new Database(SQLITE_PATH, { readonly: true });
const pool = new pg.Pool({ connectionString: POSTGRES_URL });

// Tables in FK-dependency order (parents before children)
const MIGRATION_ORDER = [
  'users',
  'sessions',
  'projects',
  'agents',
  'settings',
  'orchestration_plans',
  'plan_items',
  'project_memory',
  'global_memory',
  'github_issue_sync',
  'agent_sessions',
  'agent_jobs',
  'credentials',
  'notifications',
  'beads',
  'bead_comments',
  'project_members',
  'project_invitations',
  'bead_sync_state',
  'activity_log',
  'drains',
  'worktree_runs',
  'github_installations',
  'github_installation_repos',
  'project_agent_config',
  'api_tokens',
  'organizations',
  'organization_members',
  'organization_invitations',
  'teams',
  'team_members',
  'team_projects',
  'sso_identity_links',
  'org_audit_log',
  'auth_events',
  'readiness_outcomes',
];

// Primary key column(s) for each table — used for ON CONFLICT target in upsert mode
const PRIMARY_KEYS: Record<string, string[]> = {
  users: ['id'],
  sessions: ['id'],
  projects: ['id'],
  agents: ['id'],
  settings: ['user_id', 'key'],
  orchestration_plans: ['id'],
  plan_items: ['id'],
  project_memory: ['id'],
  global_memory: ['id'],
  github_issue_sync: ['id'],
  agent_sessions: ['id'],
  agent_jobs: ['id'],
  credentials: ['id'],
  notifications: ['id'],
  beads: ['id'],
  bead_comments: ['id'],
  project_members: ['project_id', 'user_id'],
  project_invitations: ['id'],
  bead_sync_state: ['project_id'],
  activity_log: ['id'],
  drains: ['id'],
  worktree_runs: ['id'],
  github_installations: ['installation_id'],
  github_installation_repos: ['installation_id', 'repo_id'],
  project_agent_config: ['project_id'],
  api_tokens: ['id'],
  organizations: ['id'],
  organization_members: ['org_id', 'user_id'],
  organization_invitations: ['id'],
  teams: ['id'],
  team_members: ['team_id', 'user_id'],
  team_projects: ['team_id', 'project_id'],
  sso_identity_links: ['id'],
  org_audit_log: ['id'],
  auth_events: ['id'],
  readiness_outcomes: ['id'],
};

// Boolean columns that need 0/1 → true/false conversion
const BOOLEAN_COLUMNS: Record<string, Set<string>> = {
  users: new Set(['onboarding_completed']),
  projects: new Set(['github_sync_enabled', 'auto_dispatch_ready']),
  notifications: new Set(['read']),
  organizations: new Set(['sso_enforced']),
  organization_members: new Set(['sso_linked']),
  github_installation_repos: new Set(['private']),
  worktree_runs: new Set(['analyzed']),
  beads: new Set(['escalated']),
  readiness_outcomes: new Set(['auto_readied']),
};

function convertValue(table: string, column: string, value: any): any {
  if (value === null || value === undefined) return null;

  // Boolean conversion
  if (BOOLEAN_COLUMNS[table]?.has(column)) {
    return value === 1 || value === true || value === '1';
  }

  return value;
}

function buildSQL(table: string, columns: string[]): string {
  const quotedCols = columns.map(c => `"${c}"`).join(', ');
  const placeholders = columns.map((_, i) => `$${i + 1}`).join(', ');
  const pkCols = PRIMARY_KEYS[table];

  if (UPSERT && pkCols) {
    // ON CONFLICT (pk) DO UPDATE SET all non-pk columns
    const nonPkCols = columns.filter(c => !pkCols.includes(c));
    if (nonPkCols.length === 0) {
      // Table is all PK (rare) — just do nothing
      return `INSERT INTO "${table}" (${quotedCols}) VALUES (${placeholders}) ON CONFLICT DO NOTHING`;
    }
    const conflictTarget = pkCols.map(c => `"${c}"`).join(', ');
    const updateSet = nonPkCols.map(c => `"${c}" = EXCLUDED."${c}"`).join(', ');
    return `INSERT INTO "${table}" (${quotedCols}) VALUES (${placeholders}) ON CONFLICT (${conflictTarget}) DO UPDATE SET ${updateSet}`;
  }

  return `INSERT INTO "${table}" (${quotedCols}) VALUES (${placeholders}) ON CONFLICT DO NOTHING`;
}

async function migrateTable(table: string): Promise<{ inserted: number; updated: number }> {
  let rows: any[];
  try {
    rows = sqlite.prepare(`SELECT * FROM ${table}`).all();
  } catch (e: any) {
    if (e.message?.includes('no such table')) {
      console.log(`  ⏭️  ${table}: not in SQLite (skipping)`);
      return { inserted: 0, updated: 0 };
    }
    throw e;
  }

  if (rows.length === 0) {
    console.log(`  ⏭���  ${table}: 0 rows (skipping)`);
    return { inserted: 0, updated: 0 };
  }

  if (DRY_RUN) {
    console.log(`  📋 ${table}: ${rows.length} rows (dry run)`);
    return { inserted: rows.length, updated: 0 };
  }

  const columns = Object.keys(rows[0]);
  const sqlStr = buildSQL(table, columns);

  let inserted = 0;
  let updated = 0;
  let skipped = 0;

  for (const row of rows) {
    const values = columns.map(col => convertValue(table, col, row[col]));
    try {
      const result = await pool.query(sqlStr, values);
      if (result.rowCount && result.rowCount > 0) {
        // In upsert mode, we can't easily distinguish insert vs update
        // from rowCount alone, but rowCount > 0 means the row is current
        inserted++;
      } else {
        skipped++;
      }
    } catch (e: any) {
      console.error(`  ❌ ${table} row error:`, e.message);
      console.error(`     Row:`, JSON.stringify(row).substring(0, 200));
      skipped++;
    }
  }

  const mode = UPSERT ? 'upserted' : 'inserted';
  const skipMsg = skipped > 0 ? ` (${skipped} skipped/errors)` : '';
  console.log(`  ✅ ${table}: ${inserted}/${rows.length} ${mode}${skipMsg}`);
  return { inserted, updated };
}

async function main() {
  console.log('=== SQLite ��� Postgres Data Migration ===\n');
  console.log(`Source: ${SQLITE_PATH}`);
  console.log(`Target: ${POSTGRES_URL?.replace(/:[^@]+@/, ':***@')}`);
  if (DRY_RUN) console.log('Mode: DRY RUN (no data will be written)');
  if (TRUNCATE) console.log('Mode: TRUNCATE (target tables will be cleared first)');
  if (UPSERT) console.log('Mode: UPSERT (existing rows will be updated)');
  console.log('');

  // Verify SQLite is readable
  try {
    const userCount = sqlite.prepare('SELECT COUNT(*) as count FROM users').get() as any;
    console.log(`SQLite has ${userCount.count} users\n`);
  } catch (e: any) {
    console.error('Failed to read SQLite database:', e.message);
    process.exit(1);
  }

  // Verify Postgres is reachable
  try {
    await pool.query('SELECT 1');
    console.log('Postgres connection OK\n');
  } catch (e: any) {
    console.error('Failed to connect to Postgres:', e.message);
    process.exit(1);
  }

  // Truncate if requested
  if (TRUNCATE && !DRY_RUN) {
    console.log('Truncating all tables...');
    const reversed = [...MIGRATION_ORDER].reverse();
    await pool.query(`TRUNCATE TABLE ${reversed.map(t => `"${t}"`).join(', ')} CASCADE`);
    console.log('Done.\n');
  }

  // Migrate each table
  console.log('Migrating tables:\n');
  let totalInserted = 0;

  for (const table of MIGRATION_ORDER) {
    const { inserted } = await migrateTable(table);
    totalInserted += inserted;
  }

  console.log(`\n=== Migration Complete ===`);
  console.log(`Total rows ${UPSERT ? 'upserted' : 'inserted'}: ${totalInserted}`);

  if (!DRY_RUN) {
    console.log('\nRun validate-migration.ts to verify data integrity.');
  }

  sqlite.close();
  await pool.end();
}

main().catch(err => {
  console.error('Migration failed:', err);
  process.exit(1);
});

