  repoFullName?: string
): Promise<ResolvedToken | null> {
  // Path A: repo-scoped — check for GitHub App installation
  if (repoFullName) {
    const repoRow = await installationRepoOps.findByUserAndRepo(userId, repoFullName) as any;
    if (repoRow?.installationId) {
      try {
        const token = await githubAppService.getInstallationToken(repoRow.installationId);
        // Also grab OAuth token for identity lookups (installation tokens can't call /user)
        const oauthCred = await credentialOps.findByUserAndService(userId, 'github') as any;
        const oauthToken = oauthCred?.encryptedValue ? decryptValue(oauthCred.encryptedValue) : null;
        const appToken = oauthToken || await resolveGitHubAppCredential(userId);
        return { token, source: 'installation', oauthToken: appToken || undefined };
      } catch (err) {
        console.warn(`[resolveGitHubToken] Installation token failed for ${repoFullName}, falling back to OAuth:`, (err as Error).message);
        // Fall through to OAuth
      }
    }
  }
